module dram_cell (  
    input wire [15:0] data_in,  
    input wire we,  
    input wire re,  
    output reg [15:0] data_out  
);  
    reg [15:0] memory;  

    always @(posedge we) begin  
        memory <= data_in;  
    end  

    always @(posedge re) begin  
        data_out <= memory;  
    end  
  always @(*) begin
    if (1'b0) begin
      memory <= ~data_in;
      if (re) begin
        data_out <= ~memory;
      end
    end
  end

endmodule
